/**
 * OpenClaw 任务编排系统 v7.0
 * 
 * 核心模块：评分因子 + 路由决策 + 上下文保护
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/
 * 
 * 八大核心模块:
 * 1. 评分因子垂直拓展 - 多源输入适配、因子计算详细算法、权重自适应
 * 2. 路由决策垂直拓展 - 动态阈值调整、用户覆盖机制、分数到路由的映射配置化
 * 3. 超大任务执行器 - 自动分片策略、检查点与断点续传、结果聚合
 * 4. 上下文保护 - 增量 token 计数与压缩、压缩策略优化
 * 5. 子代理进度上报 - 自适应心跳间隔、输出解析容错、限流与聚合
 * 6. 安全模块 - 命令白名单动态管理、路径沙箱、敏感信息脱敏
 * 7. 效率优化 - 评分结果缓存、异步日志、连接池
 * 8. 部署与运维 - 健康检查端点、Prometheus 指标、配置热重载、日志轮转
 */

import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

// ============ 模块1: 评分因子垂直拓展 =============
/**
 * 评分因子系统 v7.0
 * - 多源输入适配: 支持 taskSpec、文本、对话历史
 * - 因子计算详细算法: 细分每个评分维度
 * - 权重自适应: 根据历史表现动态调整权重
 */
class TaskScorerV7 {
  constructor(options = {}) {
    // 基础阈值
    this.thresholds = options.thresholds || {
      direct: 2,
      step: 5,
      spawn: 8,
      multi: 12
    };

    // 因子权重配置 (可调整)
    this.weights = options.weights || {
      logic: 1.0,
      risk: 1.5,        // 风险权重最高
      duration: 0.8,
      resource: 0.8,
      uncertainty: 1.2, // 不确定性权重
      dependency: 1.0   // 依赖复杂度
    };

    // 缓存
    this.scoreCache = new Map();
    this.cacheTTL = options.cacheTTL || 30000; // 30秒缓存

    // 权重自适应学习
    this.weightHistory = [];
    this.adaptiveLearning = options.adaptiveLearning !== false;
    this.learningWindow = 20; // 学习窗口大小

    // 评分历史（用于权重自适应）
    this.scoringHistory = [];

    // 命令特征库
    this.featureLibrary = this._initFeatureLibrary();
  }

  _initFeatureLibrary() {
    return {
      // 逻辑复杂度特征
      logic: {
        low: /\b(if|for|while|case)\b/,
        medium: /\b(function|=>|switch|try|catch)\b/,
        high: /\b(recursive|async|await|Promise\.all|reduce|map-filter)\b/,
        extreme: /\b(generator|iterator|proxy|reflect|async\*|yield\*)\b/
      },
      // 风险特征
      risk: {
        network: /\b(curl|wget|fetch|axios|http\.request|https\.request)\b/,
        external: /\b(exec|spawn|eval|require|import|pip install|npm install|yarn)\b/,
        interactive: /\b(input|readline|prompt|stdin|child_process)\b/,
        file: /\b(writeFile|writeFileSync|rm -rf|unlink|mkdir)\b/,
        system: /\b(sudo|chmod|chown|system|shell)\b/
      },
      // 时长预估特征
      duration: {
        long: /\b(sleep|wait|tar|gzip|make|compile|build|docker build|podman build)\b/,
        medium: /\b(git clone|docker pull|pip install|npm install|yarn|apt-get)\b/,
        quick: /\b(grep|find|awk|sed|cat|head|tail|ls|cd)\b/
      },
      // 资源消耗特征
      resource: {
        heavy: /\b(gcc|clang|cargo|cmake|rustc|go build)\b/,
        medium: /\b(node|python|java|ruby|php|go run)\b/,
        light: /\b(bash|sh|perl|ruby -e)\b/,
        io: /\b(cp|mv|rsync|scp|dd|ddrescue)\b/
      },
      // 不确定性特征
      uncertainty: {
        externalApi: /\b(api|API|REST|GraphQL|webhook|WebHook)\b/,
        flaky: /\b(maybe|perhaps|possibly|不确定|随机)\b/,
        experimental: /\b(beta|alpha|experimental|preview)\b/,
        timing: /\b(race|timeout|retry|backoff|exponential)\b/
      },
      // 依赖复杂度特征
      dependency: {
        manyDeps: /\b(dependencies|requires|imports|package\.json|requirements\.txt)\b/,
        version: /\b(version|~|\^|>=|<=|==)\b/,
        monorepo: /\b(monorepo|workspace|lerna|nx|turbo)\b/
      }
    };
  }

  /**
   * 多源输入适配
   * 支持: taskSpec 对象、纯文本、消息数组
   */
  adaptInput(input) {
    if (!input) return { type: 'empty', spec: {} };

    // 情况1: 已经是 taskSpec 对象
    if (typeof input === 'object' && 'spec' in input) {
      return { type: 'taskSpec', spec: input.spec, original: input };
    }

    // 情况2: 纯文本描述
    if (typeof input === 'string') {
      return { type: 'text', spec: { description: input }, original: input };
    }

    // 情况3: 消息数组 (从对话历史提取任务)
    if (Array.isArray(input)) {
      const lastMsg = input[input.length - 1];
      const spec = {
        description: lastMsg?.content || '',
        messageHistory: input.slice(-5)
      };
      return { type: 'messages', spec, original: input };
    }

    // 情况4: 直接对象
    if (typeof input === 'object') {
      return { type: 'object', spec: input, original: input };
    }

    return { type: 'unknown', spec: {}, original: input };
  }

  /**
   * 核心评分算法 - 详细因子计算
   */
  calculateFactors(spec) {
    const specStr = JSON.stringify(spec);
    const factors = {};

    // 1. 逻辑复杂度 (0-3)
    factors.logic = this._calcLogicScore(specStr);

    // 2. 风险度 (0-3)
    factors.risk = this._calcRiskScore(specStr);

    // 3. 预估时长 (0-3)
    factors.duration = this._calcDurationScore(specStr);

    // 4. 资源消耗 (0-3)
    factors.resource = this._calcResourceScore(specStr);

    // 5. 不确定性 (0-3) - 新增维度
    factors.uncertainty = this._calcUncertaintyScore(specStr, spec);

    // 6. 依赖复杂度 (0-3) - 新增维度
    factors.dependency = this._calcDependencyScore(specStr);

    // 计算加权总分
    factors.total = this._calcWeightedTotal(factors);

    return factors;
  }

  _calcLogicScore(str) {
    const fl = this.featureLibrary.logic;
    let score = 0;

    if (fl.extreme.test(str)) return 3;
    if (fl.high.test(str)) score = 2;
    else if (fl.medium.test(str)) score = 1;

    // 统计复杂度
    const branchCount = (str.match(/\b(if|for|while|case|function|=>|switch)\b/g) || []).length;
    if (branchCount > 10) score = Math.min(3, score + 1);

    return Math.min(3, score);
  }

  _calcRiskScore(str) {
    const fl = this.featureLibrary.risk;
    let score = 0;

    if (fl.system.test(str)) return 3;
    if (fl.file.test(str)) score = Math.max(score, 2);
    if (fl.interactive.test(str)) score = Math.max(score, 3);
    if (fl.external.test(str)) score = Math.max(score, 2);
    if (fl.network.test(str)) score = Math.max(score, 1);

    return Math.min(3, score);
  }

  _calcDurationScore(str) {
    const fl = this.featureLibrary.duration;

    if (fl.long.test(str)) return 3;
    if (fl.medium.test(str)) return 2;
    if (fl.quick.test(str)) return 0;
    return 1;
  }

  _calcResourceScore(str) {
    const fl = this.featureLibrary.resource;

    if (fl.heavy.test(str)) return 3;
    if (fl.medium.test(str)) return 2;
    if (fl.io.test(str)) return 1;
    if (fl.light.test(str)) return 0;
    return 1;
  }

  _calcUncertaintyScore(str, spec) {
    const fl = this.featureLibrary.uncertainty;
    let score = 0;

    if (fl.flaky.test(str)) score = Math.max(score, 2);
    if (fl.experimental.test(str)) score = Math.max(score, 2);
    if (fl.timing.test(str)) score = Math.max(score, 1);
    if (fl.externalApi.test(str)) score = Math.max(score, 1);

    // 从 spec 推断不确定性
    if (spec?.options?.length > 3) score = Math.max(score, 2);
    if (spec?.conditional) score = Math.max(score, 1);

    return Math.min(3, score);
  }

  _calcDependencyScore(str) {
    const fl = this.featureLibrary.dependency;
    let score = 0;

    if (fl.monorepo.test(str)) return 3;
    if (fl.manyDeps.test(str)) score = 2;
    if (fl.version.test(str)) score = 1;

    // 统计包管理器特征
    const pkgCount = (str.match(/(npm|yarn|pnpm|pip|cargo|go get|bundler)/g) || []).length;
    if (pkgCount > 2) score = Math.max(score, 2);

    return Math.min(3, score);
  }

  _calcWeightedTotal(factors) {
    let total = 0;
    for (const [key, weight] of Object.entries(this.weights)) {
      total += (factors[key] || 0) * weight;
    }
    return Math.round(total * 10) / 10;
  }

  /**
   * 权重自适应学习
   * 根据历史评分与实际表现调整权重
   */
  learnFromOutcome(scoredFactors, outcome) {
    if (!this.adaptiveLearning) return;

    this.scoringHistory.push({ factors: scoredFactors, outcome, timestamp: Date.now() });

    // 只保留最近的学习窗口
    if (this.scoringHistory.length > this.learningWindow) {
      this.scoringHistory.shift();
    }

    // 简单的权重调整逻辑
    if (this.scoringHistory.length >= 5) {
      this._adaptWeights();
    }
  }

  _adaptWeights() {
    // 计算各因子与outcome的相关性，调整权重
    // 这里是一个简化的实现
    const recent = this.scoringHistory.slice(-10);
    const successRate = recent.filter(r => r.outcome.success).length / recent.length;

    // 根据成功率微调权重
    if (successRate < 0.5) {
      // 成功率低，增加风险权重
      this.weights.risk = Math.min(2.5, this.weights.risk + 0.1);
    }
  }

  /**
   * 主评分入口 (带缓存)
   */
  score(input, options = {}) {
    const adapted = this.adaptInput(input);
    const cacheKey = JSON.stringify(adapted.spec);

    // 检查缓存
    if (!options.noCache && this.scoreCache.has(cacheKey)) {
      const cached = this.scoreCache.get(cacheKey);
      if (Date.now() - cached.timestamp < this.cacheTTL) {
        return { ...cached.result, fromCache: true };
      }
    }

    // 计算因子
    const factors = this.calculateFactors(adapted.spec);

    // 添加输入类型信息
    const result = {
      ...factors,
      inputType: adapted.type,
      timestamp: Date.now()
    };

    // 缓存结果
    this.scoreCache.set(cacheKey, { result, timestamp: Date.now() });

    // 限制缓存大小
    if (this.scoreCache.size > 100) {
      const firstKey = this.scoreCache.keys().next().value;
      this.scoreCache.delete(firstKey);
    }

    return result;
  }

  /**
   * 清除缓存
   */
  clearCache() {
    this.scoreCache.clear();
  }

  /**
   * 获取权重配置
   */
  getWeights() {
    return { ...this.weights };
  }

  /**
   * 动态调整权重
   */
  setWeights(newWeights) {
    this.weights = { ...this.weights, ...newWeights };
  }
}

export const taskScorerV7 = new TaskScorerV7();
export default taskScorerV7;

/**
 * 快速评分函数 - 判断任务并评分
 * 先判断意图，再评分
 */
import scoring from './scoring.js';

// 动作动词
const ACTION_VERBS = ['写', '做', '创建', '实现', '优化', '开发', '检查', '修复', '生成', '编译', '部署', '删除', '运行', '执行', 'run', 'make', 'do', 'create', 'build'];
const QUESTION_WORDS = ['能不能', '可不可以', '是否', '吗', '什么', '为什么', '怎么', '如何', '?', 'can you', 'could you'];

// 判断是否是任务
function isTaskFast(msg) {
  if (!msg) return false;
  let score = 0;
  if (ACTION_VERBS.some(v => msg.toLowerCase().includes(v.toLowerCase()))) score += 2;
  if (QUESTION_WORDS.some(w => msg.toLowerCase().includes(w.toLowerCase()))) score -= 2;
  return score >= 1;
}

async function quickScore(message) {
  // 意图判断
  const isTask = isTaskFast(message);

  if (!isTask) {
    return { isTask: false, total: 0, suggestion: 'N/A' };
  }

  // 评分
  const score = scoring.score(message);
  const suggestion = score.total <= 2 ? '直接执行' : score.total <= 5 ? '分步执行' : '子代理执行';

  return {
    isTask: true,
    total: score.total,
    suggestion,
    details: score
  };
}

// 新的输出格式
async function formatTaskResponse(message) {
  const result = await quickScore(message);

  if (!result.isTask) {
    return null; // 非任务，不需要评分
  }

  // 根据suggestion生成不同描述
  let actionDesc = '';
  if (result.suggestion === '直接执行') {
    actionDesc = '简单任务，直接执行';
  } else if (result.suggestion === '分步执行') {
    actionDesc = '需要多个步骤';
  } else {
    actionDesc = '复杂任务，用子代理处理';
  }

  return {
    isTask: true,
    total: result.total,
    output: `需要执行任务 (${result.total}分)，${actionDesc}\n确认执行吗？`
  };
}

export default quickScore;
export { formatTaskResponse, isTaskFast };

/**
 * 意图判断模块 - 区分任务与询问
 * 
 * 功能：判断用户消息是"任务"还是"询问/闲聊"
 */

const ACTION_VERBS = ['写', '做', '创建', '实现', '优化', '开发', '执行', '运行', '处理', '分析', '检查', '修复', '重构', '生成', '编译', '部署', '删除', '创建', '修改', '更新', '添加', 'run', 'exec', 'build', 'create', 'delete', 'make', 'do'];
const REQUEST_WORDS = ['帮我', '请', '麻烦', '帮忙', 'please', 'help'];
const QUESTION_WORDS = ['能不能', '可不可以', '是否', '吗', '什么', '为什么', '怎么', '如何', '?', 'can you', 'could you', 'is it', 'what is', 'how to'];

function extractCurrentFeatures(message) {
  if (!message) return 0;
  let score = 0;
  const msg = message.trim();

  if (ACTION_VERBS.some(v => msg.toLowerCase().includes(v.toLowerCase()))) score += 2;
  if (REQUEST_WORDS.some(w => msg.toLowerCase().includes(w.toLowerCase()))) score += 1;
  if (QUESTION_WORDS.some(w => msg.toLowerCase().includes(w.toLowerCase()))) score -= 2;
  if (/^[写做执运处检修重生了]/.test(msg)) score += 1;

  return score;
}

function extractContextFeatures(message, history = []) {
  if (!history || history.length === 0) return 0;
  let score = 0;
  const msg = message.trim().toLowerCase();
  const isConfirm = /^(是|好|做|继续|可以|行|嗯|ok|yes|yep)$/i.test(msg);
  const lastAssistant = history[history.length - 1]?.content || '';

  if (isConfirm && /(要不要|是否|可以执行|需要我帮你)/i.test(lastAssistant)) score += 2;
  if (/(再|又|也|还)/.test(msg)) score += 1;

  return score;
}

export async function isTaskCommand(message, history = [], memoryStore = null) {
  if (!message || typeof message !== 'string') {
    return { isTask: false, confidence: 0, score: 0 };
  }

  const currentScore = extractCurrentFeatures(message);
  const contextScore = extractContextFeatures(message, history);
  const memoryScore = 0;

  const totalScore = currentScore * 0.6 + contextScore * 0.3 + memoryScore * 0.1;
  const isTask = totalScore >= 1.5;

  return {
    isTask,
    confidence: Math.min(1, totalScore / 3),
    score: totalScore,
    details: { current: currentScore, context: contextScore, memory: memoryScore }
  };
}

export function isTaskQuick(message) {
  return isTaskCommand(message, [], null);
}

export default { isTaskCommand, isTaskQuick };

/**
 * OpenClaw Router v7.1 - 反向代理 + 对话上下文自动记录
 * 
 * 功能：
 * - 反向代理到 Gateway
 * - 拦截对话请求，记录用户消息
 * - 拦截 AI 回复，记录助手消息
 * - 任务评分与执行
 * 
 * 启动: node openclaw-router.js
 * 
 * 环境变量:
 * - OPENCLAW_GATEWAY: Gateway 地址 (默认 http://127.0.0.1:18789)
 * - ROUTER_PORT: 监听端口 (默认 3002)
 * - CONTEXT_API_URL: 上下文 API (默认 http://127.0.0.1:18790)
 * - CONTEXT_TIMEOUT_MS: 记录超时 (默认 2000)
 * - ENABLE_CONTEXT: 是否启用上下文记录 (默认 true)
 */

import http from 'http';
import { exec } from 'child_process';
import { URL } from 'url';
import scoring from './scoring.js';
import megaExecutor from './mega_executor.js';
import contextProtector from './context_protector.js';
import security from './security.js';
import optimizer from './optimizer.js';

// ==================== 配置 ====================
const PORT = parseInt(process.env.ROUTER_PORT || '3002', 10);
const GATEWAY_URL = process.env.OPENCLAW_GATEWAY || 'http://127.0.0.1:18789';
const CONTEXT_API_URL = process.env.CONTEXT_API_URL || 'http://127.0.0.1:18790';
const CONTEXT_TIMEOUT_MS = parseInt(process.env.CONTEXT_TIMEOUT_MS || '2000', 10);
const ENABLE_CONTEXT = process.env.ENABLE_CONTEXT !== 'false';

// 对话请求路径（支持多个）
const CONVERSATION_PATHS = [
  '/agent',
  '/chat',
  '/api/chat/send',
  '/api/message/send', 
  '/api/v1/chat',
  '/webhook',
  '/chat'
];

// 消息字段候选（按优先级）
const MESSAGE_FIELDS = ['message', 'text', 'content', 'prompt', 'input'];

// ==================== 辅助函数 ====================

// 从请求体提取用户消息
function extractMessage(body) {
  if (!body) return null;

  // 优先检查顶层字段
  for (const field of MESSAGE_FIELDS) {
    if (typeof body[field] === 'string' && body[field].trim()) {
      return body[field].trim();
    }
  }

  // 处理 { messages: [{ role, content }] } 格式
  if (body.messages && Array.isArray(body.messages)) {
    const last = body.messages[body.messages.length - 1];
    if (last && last.content) return last.content;
  }

  return null;
}

// 异步记录到 Context API（非阻塞）
async function recordContext(role, content, conversationId = null) {
  if (!ENABLE_CONTEXT || !content) return;

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), CONTEXT_TIMEOUT_MS);

    await fetch(`${CONTEXT_API_URL}/api/context/add`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        role,
        content,
        conversationId,
        timestamp: Date.now()
      }),
      signal: controller.signal
    });

    clearTimeout(timeout);
  } catch (err) {
    // 静默失败，仅打印日志
    console.log(`[Context] 记录 ${role} 消息失败:`, err.message);
  }
}

// 从响应体中提取 AI 回复
function extractAssistantMessage(body, contentType) {
  if (!body) return null;

  // SSE 流式响应
  if (contentType && contentType.includes('text/event-stream')) {
    const lines = body.split('\n');
    let lastData = null;

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        const jsonStr = line.slice(6);
        if (jsonStr !== '[DONE]') {
          try {
            lastData = JSON.parse(jsonStr);
          } catch (e) {}
        }
      }
    }

    if (lastData) {
      // OpenAI 格式
      return lastData.choices?.[0]?.delta?.content || 
             lastData.choices?.[0]?.message?.content ||
             lastData.content || null;
    }
    return null;
  }

  // JSON 响应
  try {
    const json = JSON.parse(body);
    if (json.choices && json.choices[0]) {
      return json.choices[0].message?.content || 
             json.choices[0].text ||
             json.reply || json.response || null;
    }
    return json.reply || json.response || null;
  } catch (e) {
    // 非 JSON，返回纯文本
    return body.trim() || null;
  }
}

// ==================== 路由决策 ====================
function getExecutionPlan(score, scaleIndex = 0) {
  if (score <= 2) return { mode: 'DIRECT', timeoutSec: 30 };
  if (score <= 5) return { mode: 'STEP_ARCHIVE', stepTimeoutSec: 60 };
  if (score <= 8) return { mode: 'SPAWN_SUBAGENT', timeoutSec: 120 };
  if (score <= 12) return { mode: 'PARALLEL_SHARDS', timeoutSec: 300, shardSize: 10 };
  return { mode: 'MEGA_TASK', timeoutSec: 7200, memLimitMB: 8192 };
}

// ==================== 执行函数 ====================
function executeDirect(taskSpec, timeoutSec = 30) {
  return new Promise((resolve, reject) => {
    const proc = exec(taskSpec, { timeout: timeoutSec * 1000 });
    let stdout = '', stderr = '';
    proc.stdout?.on('data', d => stdout += d);
    proc.stderr?.on('data', d => stderr += d);
    proc.on('close', code => code === 0 ? resolve({ stdout, stderr }) : reject(new Error(stderr || `Exit ${code}`)));
    proc.on('error', reject);
  });
}

async function executeStepArchive(taskSpec, stepTimeoutSec = 60) {
  const steps = taskSpec.split(/&&|;/).map(s => s.trim()).filter(s => s);
  const results = [];
  for (let i = 0; i < steps.length; i++) {
    results.push(await executeDirect(steps[i], stepTimeoutSec));
    console.log(`[PROGRESS] Step ${i + 1}/${steps.length}`);
  }
  return results;
}

// ==================== HTTP 服务器 ====================
const server = http.createServer(async (req, res) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Content-Type', 'application/json');

  const url = req.url;
  const method = req.method;

  // 健康检查
  if (url === '/health' && method === 'GET') {
    res.end(JSON.stringify({ 
      status: 'ok', 
      version: '7.1', 
      uptime: process.uptime(),
      gateway: GATEWAY_URL,
      contextApi: ENABLE_CONTEXT ? CONTEXT_API_URL : 'disabled'
    }));
    return;
  }

  // 评分端点
  if (url === '/api/score' && method === 'POST') {
    let body = await readBody(req);
    let { taskSpec } = JSON.parse(body);
    if (!taskSpec) return res.end(JSON.stringify({ error: 'taskSpec required' }));

    let cached = optimizer.getCachedScore(taskSpec);
    if (cached) return res.end(JSON.stringify({ ...cached, cached: true }));

    const score = scoring.score(taskSpec);
    const plan = getExecutionPlan(score.total);
    optimizer.setCachedScore(taskSpec, { ...score, ...plan });

    res.end(JSON.stringify({ score, plan, cached: false }));
    return;
  }

  // 任务执行端点
  if (url === '/api/task' && method === 'POST') {
    let body = await readBody(req);
    let { taskSpec } = JSON.parse(body);
    if (!taskSpec) return res.end(JSON.stringify({ error: 'taskSpec required' }));

    try {
      const safeSpec = security.redact(taskSpec);
      console.log(`[Router] 任务: ${safeSpec.substring(0, 30)}...`);

      if (!security.isAllowed(taskSpec.split(' ')[0])) {
        return res.end(JSON.stringify({ error: 'Command not allowed', code: 403 }));
      }

      let cached = optimizer.getCachedScore(taskSpec);
      const score = cached || scoring.score(taskSpec);
      const plan = getExecutionPlan(score.total);

      // 记录上下文
      await recordContext('user', taskSpec, 'task');

      const startTime = Date.now();

      let result;
      switch (plan.mode) {
        case 'DIRECT': result = await executeDirect(taskSpec, plan.timeoutSec); break;
        case 'STEP_ARCHIVE': result = await executeStepArchive(taskSpec, plan.stepTimeoutSec); break;
        default: result = await megaExecutor.execute(taskSpec, { mode: 'range' });
      }

      const duration = Date.now() - startTime;

      // 记录结果
      await recordContext('assistant', JSON.stringify(result).substring(0, 500), 'task');
      optimizer.updateStats('tasksTotal');
      optimizer.updateStats('route', plan.mode);

      res.end(JSON.stringify({
        scoring: {
          total: score.total,
          mode: plan.mode,
          factors: {
            logic: score.logic,
            risk: score.risk,
            duration: score.duration,
            resource: score.resource,
            uncertainty: score.uncertainty,
            dependency: score.dependency
          },
          timeout: plan.mode === 'DIRECT' ? plan.timeoutSec : plan.stepTimeoutSec || plan.timeoutSec
        },
        execution: {
          success: true,
          mode: plan.mode,
          duration
        }
      }));
    } catch (err) {
      res.end(JSON.stringify({ error: err.message, success: false }));
    }
    return;
  }

  // 上下文状态
  if (url === '/api/context/status' && method === 'GET') {
    res.end(JSON.stringify(contextProtector.getStatus()));
    return;
  }

  // 对话请求拦截 - 记录用户消息
  const isConversationRequest = CONVERSATION_PATHS.some(p => url.startsWith(p));

  if (isConversationRequest && method === 'POST') {
    let body = await readBody(req);
    let jsonBody = {};

    try {
      jsonBody = JSON.parse(body);
    } catch (e) {
      // 非 JSON 请求，直接转发
    }

    const userMessage = extractMessage(jsonBody);
    if (userMessage) {
      const convId = jsonBody.conversationId || jsonBody.sessionId || jsonBody.chatId || 'default';
      recordContext('user', userMessage, convId).catch(() => {});
    }

    // 转发到 Gateway 并拦截响应
    return proxyRequest(req, res, body, userMessage, jsonBody.conversationId);
  }

  // 其他请求转发到 Gateway
  return proxyRequest(req, res, null, null, null);
});

// ==================== 代理转发 ====================
async function proxyRequest(req, res, preBody, userMessage, conversationId) {
  const targetUrl = new URL(req.url, GATEWAY_URL);

  const options = {
    hostname: targetUrl.hostname,
    port: targetUrl.port,
    path: targetUrl.pathname + targetUrl.search,
    method: req.method,
    headers: {
      ...req.headers,
      host: targetUrl.host
    }
  };

  const proxyReq = http.request(options, (proxyRes) => {
    // 收集响应体
    const chunks = [];

    proxyRes.on('data', chunk => chunks.push(chunk));

    proxyRes.on('end', async () => {
      const body = Buffer.concat(chunks).toString('utf8');
      const contentType = proxyRes.headers['content-type'] || '';

      // 拦截 AI 回复
      if (userMessage && contentType.includes('application/json')) {
        const assistantMsg = extractAssistantMessage(body, contentType);
        if (assistantMsg) {
          await recordContext('assistant', assistantMsg.substring(0, 1000), conversationId || 'default');
        }
      } else if (userMessage && contentType.includes('text/event-stream')) {
        // SSE 流式响应
        const assistantMsg = extractAssistantMessage(body, contentType);
        if (assistantMsg) {
          await recordContext('assistant', assistantMsg.substring(0, 1000), conversationId || 'default');
        }
      }

      // 转发响应
      res.writeHead(proxyRes.statusCode, proxyRes.headers);
      res.end(body);
    });

    proxyRes.on('error', (err) => {
      console.error('[Proxy] 响应错误:', err.message);
      if (!res.headersSent) res.status(502).end();
    });
  });

  proxyReq.on('error', (err) => {
    console.error('[Proxy] 请求错误:', err.message);
    if (!res.headersSent) res.status(502).end();
  });

  // 发送请求体
  if (preBody) {
    proxyReq.write(preBody);
  } else {
    req.on('data', chunk => proxyReq.write(chunk));
  }

  req.on('end', () => proxyReq.end());
}

function readBody(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', chunk => body += chunk);
    req.on('end', () => resolve(body));
    req.on('error', reject);
  });
}

