/**
 * OpenClaw 上下文保护模块 v7.0
 * 
 * 功能：
 * - 增量 token 计数（精确计算）
 * - 智能压缩策略
 * - 检查点备份
 * - 手动触发命令
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/context_protector.js
 */

import * as fs from 'fs/promises';
import * as path from 'path';

// 存储目录
const STORAGE_DIR = path.join(process.env.HOME || '/home/ai', '.openclaw', 'context');
const BACKUP_SUFFIX = '.backup';

class ContextProtector {
  constructor(options = {}) {
    this.storageDir = options.storageDir || STORAGE_DIR;
    this.maxMessages = options.maxMessages || 50;
    this.maxChars = options.maxChars || 100 * 1024; // 100KB
    this.maxTokens = options.maxTokens || 150000;   // GPT-4 上下文限制的 80%
    this.keepRecent = options.keepRecent || 10;
    this.enableBackup = options.enableBackup !== false;

    this.messages = [];
    this.totalTokens = 0;
    this.lastCompressAt = 0;
  }

  /**
   * 初始化
   */
  async init() {
    await fs.mkdir(this.storageDir, { recursive: true });
  }

  /**
   * 添加消息（增量 token 计数）
   */
  async addMessage(role, content, metadata = {}) {
    const tokenCount = await this._countTokens(content);

    this.messages.push({
      role,
      content,
      metadata,
      timestamp: Date.now(),
      tokens: tokenCount
    });

    this.totalTokens += tokenCount;

    // 检查是否需要压缩
    if (this.shouldCompress()) {
      await this.compress();
    }

    return {
      messageCount: this.messages.length,
      totalTokens: this.totalTokens,
      shouldCompress: this.shouldCompress()
    };
  }

  /**
   * 检查是否需要压缩
   */
  shouldCompress() {
    const msgCount = this.messages.length;
    const totalChars = this.messages.reduce((sum, m) => sum + (m.content?.length || 0), 0);

    return (
      msgCount >= this.maxMessages ||
      totalChars >= this.maxChars ||
      this.totalTokens >= this.maxTokens
    );
  }

  /**
   * 增量 token 计数（简单实现，使用 TikToken 风格估算）
   * 生产环境建议使用 tiktoken 库
   */
  async _countTokens(text) {
    if (!text) return 0;

    // 简单估算：中文字符 × 2 + 英文单词 × 1.3 + 特殊字符
    const chineseChars = (text.match(/[\u4e00-\u9fa5]/g) || []).length;
    const englishWords = (text.match(/[a-zA-Z0-9_]+/g) || []).length;

    // TikToken 风格估算
    // 汉字约 1.5 tokens/字符，英文约 0.25 tokens/字符
    return Math.ceil(chineseChars * 1.5 + englishWords * 0.25 + text.length * 0.25);
  }

  /**
   * 压缩上下文
   */
  async compress(force = false) {
    if (!force && !this.shouldCompress()) {
      return { skipped: true, reason: 'Not needed' };
    }

    // 备份当前上下文
    if (this.enableBackup) {
      await this._backup();
    }

    const beforeCount = this.messages.length;
    const beforeTokens = this.totalTokens;

    // 策略1：保留最近 N 条
    const recent = this.messages.slice(-this.keepRecent);

    // 策略2：对早前的消息生成摘要
    const toSummarize = this.messages.slice(0, -this.keepRecent);

    if (toSummarize.length > 0) {
      // 生成摘要（这里使用简单实现，生产环境可调用 LLM）
      const summary = this._generateSummary(toSummarize);
      recent.unshift({
        role: 'system',
        content: `[上下文压缩] 之前的 ${toSummarize.length} 条消息已压缩为摘要：${summary}`,
        metadata: { type: 'compression_summary', originalCount: toSummarize.length },
        timestamp: Date.now(),
        tokens: await this._countTokens(summary)
      });

      this.totalTokens = recent.reduce((sum, m) => sum + m.tokens, 0);
    }

    this.messages = recent;
    this.lastCompressAt = Date.now();

    return {
      beforeCount,
      afterCount: this.messages.length,
      beforeTokens,
      afterTokens: this.totalTokens,
      compressed: toSummarize.length,
      timestamp: this.lastCompressAt
    };
  }

  /**
   * 生成简单摘要（简化版）
   */
  _generateSummary(messages) {
    // 提取关键信息
    const roles = [...new Set(messages.map(m => m.role))];
    const totalLength = messages.reduce((sum, m) => sum + (m.content?.length || 0), 0);

    return `[{${roles.join(',')}} 消息, 约 ${Math.round(totalLength/1000)}K 字符]`;
  }

  /**
   * 备份当前上下文
   */
  async _backup() {
    const backupFile = path.join(
      this.storageDir, 
      `context_${Date.now()}${BACKUP_SUFFIX}.json`
    );

    await fs.writeFile(backupFile, JSON.stringify({
      messages: this.messages,
      totalTokens: this.totalTokens,
      compressedAt: this.lastCompressAt
    }, null, 2));
  }

  /**
   * 回滚到上一个备份
   */
  async rollback() {
    const files = await fs.readdir(this.storageDir);
    const backups = files
      .filter(f => f.endsWith(BACKUP_SUFFIX + '.json'))
      .sort()
      .reverse();

    if (backups.length === 0) {
      return { success: false, reason: 'No backup found' };
    }

    const latestBackup = path.join(this.storageDir, backups[0]);
    const data = JSON.parse(await fs.readFile(latestBackup, 'utf8'));

    this.messages = data.messages;
    this.totalTokens = data.totalTokens;
    this.lastCompressAt = data.compressedAt || 0;

    return {
      success: true,
      restoredFrom: backups[0],
      messageCount: this.messages.length
    };
  }

  /**
   * 获取状态
   */
  getStatus() {
    const totalChars = this.messages.reduce((sum, m) => sum + (m.content?.length || 0), 0);

    return {
      messageCount: this.messages.length,
      totalTokens: this.totalTokens,
      totalChars,
      tokenRatio: (this.totalTokens / this.maxTokens * 100).toFixed(1) + '%',
      shouldCompress: this.shouldCompress(),
      lastCompressAt: this.lastCompressAt
    };
  }

  /**
   * 获取消息历史
   */
  getMessages(limit = null) {
    if (limit) {
      return this.messages.slice(-limit);
    }
    return this.messages;
  }

  /**
   * 手动触发压缩
   */
  async summarize() {
    return this.compress(true);
  }
}

