export default megaExecutor;

/**
 * OpenClaw 安全模块 v7.0
 * 
 * 功能：
 * - 命令白名单动态管理
 * - 路径沙箱
 * - 敏感信息脱敏增强
 */

import fs from 'fs';
import path from 'path';
import { spawn } from 'child_process';

class SecurityModule {
  constructor(options = {}) {
    this.whitelistFile = options.whitelistFile || 
      path.join(process.env.HOME || '/home/ai', '.openclaw', 'security_whitelist.json');
    this.sandboxDir = options.sandboxDir || 
      path.join(process.env.HOME || '/home/ai', '.openclaw', 'sandbox');
    this.sensitivePatterns = options.sensitivePatterns || [
      /password\s*=\s*["']?[^"'\s]+["']?/gi,
      /token\s*=\s*[a-f0-9]{32,}/gi,
      /api[_-]?key\s*=\s*["']?[^"'\s]+["']?/gi,
      /Authorization:\s*Bearer\s+[a-zA-Z0-9._-]+/gi,
      /secret\s*=\s*["']?[^"'\s]+["']?/gi,
    ];
    this.whitelist = [];
    this._loadWhitelist();
  }

  _loadWhitelist() {
    try {
      if (fs.existsSync(this.whitelistFile)) {
        const data = JSON.parse(fs.readFileSync(this.whitelistFile, 'utf8'));
        this.whitelist = data.whitelist || [];
      }
    } catch (e) {
      this.whitelist = [];
    }
    // 默认白名单
    if (this.whitelist.length === 0) {
      this.whitelist = [
        '/usr/bin/ls', '/usr/bin/cat', '/usr/bin/grep', '/usr/bin/find',
        '/usr/bin/head', '/usr/bin/tail', '/usr/bin wc', '/usr/bin/sort',
        '/bin/bash', '/bin/sh', '/usr/bin/node', '/usr/bin/python3', '/usr/bin/echo', '/bin/echo', '/usr/bin/curl', '/usr/bin/wget', '/usr/bin/node', '/usr/bin/npm', '/usr/bin/pip',
      ];
    }

    // 添加命令名（去掉路径）
    const withNames = [...this.whitelist];
    for (const cmd of this.whitelist) {
      const name = cmd.split('/').pop();
      if (name && !withNames.includes(name)) {
        withNames.push(name);
      }
    }
    this.whitelist = withNames;
  }

  /** 检查命令是否在白名单 */
  isAllowed(command) {
    const cmdStr = typeof command === 'string' ? command : command.cmd;
    const parts = cmdStr.split(' ');
    const baseCmd = parts[0];

    // 检查绝对路径
    if (this.whitelist.includes(baseCmd)) return true;
    // 检查命令名匹配（去掉路径）
    const cmdName = baseCmd.split("/").pop();
    if (this.whitelist.includes(cmdName)) return true;

    // 检查正则模式
    for (const pattern of this.whitelist) {
      if (pattern.startsWith('^')) {
        const regex = new RegExp(pattern);
        if (regex.test(baseCmd)) return true;
      }
    }

    return false;
  }

  /** 路径沙箱检查 */
  safeResolve(baseDir, userPath) {
    const resolved = path.resolve(baseDir, userPath);
    if (!resolved.startsWith(baseDir)) {
      throw new Error('Path traversal detected');
    }
    return resolved;
  }

  /** 敏感信息脱敏 */
  redact(text) {
    if (!text) return text;
    let result = text;
    for (const pattern of this.sensitivePatterns) {
      result = result.replace(pattern, (match) => {
        return match.replace(/=.*/, '=***');
      });
    }
    return result;
  }

  /** 添加到白名单 */
  addToWhitelist(cmd) {
    if (!this.whitelist.includes(cmd)) {
      this.whitelist.push(cmd);
      this._saveWhitelist();
    }
  }

  /** 从白名单移除 */
  removeFromWhitelist(cmd) {
    this.whitelist = this.whitelist.filter(c => c !== cmd);
    this._saveWhitelist();
  }

  _saveWhitelist() {
    try {
      fs.mkdirSync(path.dirname(this.whitelistFile), { recursive: true });
      fs.writeFileSync(this.whitelistFile, JSON.stringify({ whitelist: this.whitelist }, null, 2));
    } catch (e) {}
  }

  /** 安全执行 */
  safeExecute(command, options = {}) {
    return new Promise((resolve, reject) => {
      if (!this.isAllowed(command)) {
        reject(new Error('Command not in whitelist'));
        return;
      }

      const cmd = typeof command === 'string' ? { shell: '/bin/bash', args: ['-c', command] } : command;

      // 脱敏日志
      const safeCmd = this.redact(cmd.args?.join(' ') || cmd.shell);
      console.log('[Security] Executing:', safeCmd);

      const child = spawn(cmd.shell, cmd.args, { stdio: 'pipe', ...options });
      let stdout = '', stderr = '';

      child.stdout.on('data', d => stdout += d);
      child.stderr.on('data', d => stderr += d);

      child.on('close', code => {
        resolve({
          code,
          stdout: this.redact(stdout),
          stderr: this.redact(stderr)
        });
      });

      child.on('error', reject);
    });
  }

  getStatus() {
    return {
      whitelistCount: this.whitelist.length,
      patternsCount: this.sensitivePatterns.length,
      sandboxDir: this.sandboxDir
    };
  }
}

export const security = new SecurityModule();
export default security;

/**
 * OpenClaw 效率优化模块 v7.0
 * 
 * 功能：
 * - 评分结果缓存 (LRU)
 * - 异步日志
 * - 健康检查端点
 */

import http from 'http';
import crypto from 'crypto';

class Optimizer {
  constructor(options = {}) {
    this.cacheTTL = options.cacheTTL || 3600000; // 1小时
    this.maxCacheKeys = options.maxCacheKeys || 1000;
    this.cache = new Map();
    this.logBuffer = [];
    this.healthPort = options.healthPort || 18791;
    this.server = null;

    // 指标统计
    this.stats = {
      cacheHits: 0,
      cacheMisses: 0,
      tasksTotal: 0,
      tasksByRoute: { DIRECT: 0, STEP_ARCHIVE: 0, SPAWN_SUBAGENT: 0, MULTI_SUBAGENT: 0 },
      compressions: 0,
    };
  }

  /** LRU 缓存 - 评分结果 */
  getCachedScore(taskSpec) {
    const key = this._hashTaskSpec(taskSpec);
    const cached = this.cache.get(key);

    if (cached && Date.now() - cached.timestamp < this.cacheTTL) {
      this.stats.cacheHits++;
      return cached.score;
    }

    this.stats.cacheMisses++;
    return null;
  }

  /** 设置缓存 */
  setCachedScore(taskSpec, score) {
    const key = this._hashTaskSpec(taskSpec);

    // LRU 淘汰
    if (this.cache.size >= this.maxCacheKeys) {
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }

    this.cache.set(key, { score, timestamp: Date.now() });
  }

  _hashTaskSpec(spec) {
    const str = typeof spec === 'string' ? spec : JSON.stringify(spec);
    return crypto.createHash('sha256').update(str).digest('hex').substring(0, 16);
  }

  /** 异步日志 - 不阻塞主线程 */
  asyncLog(message, level = 'info') {
    this.logBuffer.push({
      timestamp: Date.now(),
      level,
      message: typeof message === 'string' ? message : JSON.stringify(message)
    });

    // 异步写入（简化版，实际可用 pino/winston）
    if (this.logBuffer.length >= 10) {
      this._flushLogs();
    }
  }

  _flushLogs() {
    if (this.logBuffer.length === 0) return;
    const logs = this.logBuffer.splice(0);
    // 实际应该写入文件，这里简化为输出
    // console.log('[Optimizer] Flushed', logs.length, 'logs');
  }

  /** 启动健康检查服务 */
  startHealthServer() {
    if (this.server) return;

    this.server = http.createServer((req, res) => {
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.setHeader('Content-Type', 'application/json');

      if (req.url === '/health') {
        res.end(JSON.stringify({
          status: 'ok',
          uptime: process.uptime(),
          memory: process.memoryUsage(),
          cache: {
            size: this.cache.size,
            hits: this.stats.cacheHits,
            misses: this.stats.cacheMisses,
            hitRate: this.stats.cacheHits / (this.stats.cacheHits + this.stats.cacheMisses) * 100 || 0
          },
          tasks: this.stats
        }));
      } else if (req.url === '/metrics') {
        res.end(JSON.stringify(this.stats));
      } else {
        res.statusCode = 404;
        res.end('Not Found');
      }
    });

    this.server.listen(this.healthPort, () => {
      console.log(`[Optimizer] Health server: http://127.0.0.1:${this.healthPort}`);
    });
  }

  /** 停止健康检查服务 */
  stopHealthServer() {
    if (this.server) {
      this.server.close();
      this.server = null;
    }
  }

  /** 更新统计 */
  updateStats(type, value) {
    if (type in this.stats) {
      this.stats[type]++;
    }
    if (type === 'route' && value in this.stats.tasksByRoute) {
      this.stats.tasksByRoute[value]++;
    }
  }

  getStatus() {
    return {
      cacheSize: this.cache.size,
      cacheTTL: this.cacheTTL,
      stats: this.stats,
      healthServer: this.server ? 'running' : 'stopped'
    };
  }
}

