/**
 * 自动化项目改进系统 - 主入口
 * 
 * 接收目标，自动迭代改进直到达成或达到最大迭代次数
 * 
 * 使用方式:
 * import { autoImproveProject } from './auto_improve/autoImprove.js';
 * const result = await autoImproveProject('让代码符合ESLint标准', '/path/to/project');
 */

import { parseGoal } from './goalParser.js';
import { snapshot, restoreSnapshot, cleanupSnapshots } from './snapshot.js';
import { evaluate } from './evaluator.js';
import { generatePlan } from './planner.js';
import { applyPlan } from './executor.js';

/**
 * 自动改进项目
 * @param {string} goal - 改进目标
 * @param {string} projectPath - 项目路径
 * @param {number} maxIterations - 最大迭代次数
 * @param {Function} onProgress - 进度回调
 * @returns {Object} 最终结果
 */
export async function autoImproveProject(goal, projectPath, maxIterations = 5, onProgress = null) {
  console.log(`\n[AutoFix] 目标: ${goal}`);
  console.log(`[AutoFix] 项目: ${projectPath}`);

  // 解析目标
  const { metrics } = parseGoal(goal);
  console.log(`[AutoFix] 指标: ${metrics.map(m => m.metric).join(', ')}`);

  let iteration = 0;
  let previousPlans = [];
  let bestScore = 0;
  let bestSnapshot = null;
  let result = null;

  while (iteration < maxIterations) {
    iteration++;
    onProgress?.(`第 ${iteration} 轮迭代...`);
    console.log(`\n[AutoFix] === 第 ${iteration}/${maxIterations} 轮 ===`);

    // 1. 评估当前状态
    const evalResult = await evaluate(projectPath, metrics);
    const score = evalResult.finalScore;
    console.log(`[AutoFix] 当前达成度: ${(score * 100).toFixed(1)}%`);

    if (evalResult.isMet) {
      console.log(`[AutoFix] ✅ 目标已达成！`);
      result = { success: true, iterations: iteration, finalScore: score };
      break;
    }

    // 2. 记录最佳快照
    if (score > bestScore) {
      bestScore = score;
      bestSnapshot = await snapshot(projectPath, `best_${iteration}`);
      console.log(`[AutoFix] 已保存最佳快照 (${(score * 100).toFixed(1)}%)`);
    }

    // 3. 生成改进计划
    const plan = await generatePlan(projectPath, goal, metrics, previousPlans);
    if (plan.length === 0) {
      console.log(`[AutoFix] 无法生成改进计划`);
      break;
    }
    previousPlans.push({ iteration, plan: JSON.stringify(plan) });
    console.log(`[AutoFix] 生成计划: ${plan.length}个动作`);

    // 4. 应用计划
    const applyResult = await applyPlan(plan, projectPath);
    if (!applyResult.success) {
      console.log(`[AutoFix] 计划执行失败: ${applyResult.error}`);
      // 如果有最佳快照，回滚
      if (bestSnapshot) {
        console.log(`[AutoFix] 回滚到最佳版本`);
        await restoreSnapshot(bestSnapshot, projectPath);
      }
      continue;
    }

    console.log(`[AutoFix] 计划应用成功`);
  }

  if (iteration >= maxIterations) {
    console.log(`[AutoFix] 达到最大迭代次数 ${maxIterations}`);
    result = { success: false, iterations: maxIterations, finalScore: bestScore };
  }

  // 清理旧快照
  await cleanupSnapshots(projectPath);

  console.log(`\n[AutoFix] 完成:`, result);
  return result;
}

export default { autoImproveProject };

/**
 * evaluator.js - 评估模块
 * 评估项目在各项指标上的达成度
 */

import { existsSync } from 'fs';
import { execSync } from 'child_process';
import { readFileSync } from 'fs';
import { METRIC_TYPES } from './goalParser.js';

/**
 * 运行ESLint并返回错误数
 * @param {string} projectPath 
 * @returns {number} 错误数量
 */
function runESLint(projectPath) {
  const eslintConfig = ['.eslintrc.js', '.eslintrc.json', '.eslintrc', '.eslintrc.cjs'];
  const hasConfig = eslintConfig.some(f => existsSync(`${projectPath}/${f}`));

  if (!hasConfig && !existsSync(`${projectPath}/node_modules/.bin/eslint`)) {
    return { error: -1, message: 'ESLint not configured' };
  }

  try {
    const output = execSync('npx eslint . --max-warnings=0 --format=json 2>/dev/null || npx eslint . --format=json 2>/dev/null || echo "[]"', {
      cwd: projectPath,
      encoding: 'utf-8',
      timeout: 60000,
      maxBuffer: 10 * 1024 * 1024
    });

    const result = JSON.parse(output);
    const totalErrors = result.reduce((sum, file) => sum + file.errorCount, 0);
    return { error: 0, count: totalErrors };
  } catch (e) {
    // 尝试简单方式统计
    try {
      execSync('npx eslint . 2>&1 || true', { cwd: projectPath, encoding: 'utf-8', timeout: 60000 });
    } catch {}
    return { error: 0, count: 0 };
  }
}

/**
 * 运行测试并返回通过率
 * @param {string} projectPath 
 * @returns {object} { pass: number, total: number, rate: number }
 */
function runTests(projectPath) {
  const testScripts = ['test', 'test:ci', 'jest', 'vitest', 'mocha'];
  let testCmd = null;

  try {
    const pkg = JSON.parse(readFileSync(`${projectPath}/package.json`, 'utf-8'));
    for (const script of testScripts) {
      if (pkg.scripts && pkg.scripts[script]) {
        testCmd = script;
        break;
      }
    }
  } catch (e) {}

  if (!testCmd) {
    return { pass: 0, total: 0, rate: 100, message: 'No test script found' };
  }

  try {
    const output = execSync(`npm run ${testCmd} -- --json 2>&1 || npm run ${testCmd} 2>&1`, {
      cwd: projectPath,
      encoding: 'utf-8',
      timeout: 120000,
      maxBuffer: 10 * 1024 * 1024
    });

    // 简单解析测试结果
    const jsonMatch = output.match(/{[\s\S]*"success":\s*(true|false)[\s\S]*}/);
    if (jsonMatch) {
      const result = JSON.parse(jsonMatch[0]);
      return {
        pass: result.numPassedTests || 0,
        total: result.numTotalTests || 0,
        rate: result.success ? 100 : 0
      };
    }

    // 通过率估算
    const passMatch = output.match(/(\d+)\s+passing/);
    const failMatch = output.match(/(\d+)\s+failing/);
    const pass = passMatch ? parseInt(passMatch[1]) : 0;
    const fail = failMatch ? parseInt(failMatch[1]) : 0;
    const total = pass + fail;

    return {
      pass,
      total,
      rate: total > 0 ? Math.round((pass / total) * 100) : 100
    };
  } catch (e) {
    return { pass: 0, total: 0, rate: 0, error: e.message };
  }
}

/**
 * 评估圈复杂度
 * @param {string} projectPath 
 * @returns {object} { avg: number, max: number }
 */
function checkComplexity(projectPath) {
  // 尝试使用eslint-plugin-complexity或自定义检查
  try {
    const esFiles = execSync('find . -name "*.js" -o -name "*.ts" | head -20', {
      cwd: projectPath,
      encoding: 'utf-8'
    }).split('\n').filter(Boolean);

    let totalComplexity = 0;
    let maxComplexity = 0;
    let fileCount = 0;

    for (const file of esFiles.slice(0, 10)) {
      try {
        const content = readFileSync(`${projectPath}/${file}`, 'utf-8');
        // 简单统计圈复杂度（条件语句数量）
        const matches = content.match(/(if|for|while|switch|case|\?|&&|\|\|)/g);
        if (matches) {
          const complexity = matches.length;
          totalComplexity += complexity;
          maxComplexity = Math.max(maxComplexity, complexity);
          fileCount++;
        }
      } catch {}
    }

    return {
      avg: fileCount > 0 ? Math.round(totalComplexity / fileCount) : 0,
      max: maxComplexity
    };
  } catch (e) {
    return { avg: 0, max: 0 };
  }
}

/**
 * 综合评估
 * @param {string} projectPath - 项目路径
 * @param {Array} metrics - metrics数组
 * @returns {object} 评估结果
 */
function evaluate(projectPath, metrics) {
  const results = {};
  let totalScore = 0;
  let totalWeight = 0;

  for (const metric of metrics) {
    let result = { score: 0, value: 0, detail: {} };

    switch (metric.type) {
      case METRIC_TYPES.ESLINT: {
        const lint = runESLint(projectPath);
        const count = lint.count || 0;
        const achieved = metric.target === 0 ? (count === 0 ? 100 : Math.max(0, 100 - count * 10)) : 100;
        result = {
          score: achieved,
          value: count,
          detail: { errors: count }
        };
        break;
      }
      case METRIC_TYPES.TEST: {
        const test = runTests(projectPath);
        const achieved = test.rate >= metric.target ? 100 : (test.rate / metric.target) * 100;
        result = {
          score: achieved,
          value: test.rate,
          detail: { pass: test.pass, total: test.total }
        };
        break;
      }
      case METRIC_TYPES.COMPLEXITY: {
        const complex = checkComplexity(projectPath);
        const achieved = complex.avg <= metric.target ? 100 : Math.max(0, 100 - (complex.avg - metric.target) * 10);
        result = {
          score: achieved,
          value: complex.avg,
          detail: { avg: complex.avg, max: complex.max }
        };
        break;
      }
      case METRIC_TYPES.LLM: {
        // LLM评估需要外部调用，这里返回默认值
        result = {
          score: 50,
          value: 50,
          detail: { note: 'LLM evaluation not implemented, using default' }
        };
        break;
      }
    }

    results[metric.type] = result;
    totalScore += result.score * metric.weight;
    totalWeight += metric.weight;
  }

  const overall = totalWeight > 0 ? Math.round(totalScore / totalWeight) : 0;

  return {
    overall,
    metrics: results,
    timestamp: Date.now()
  };
}

export { evaluate, runESLint, runTests, checkComplexity };

/**
 * 执行模块 - 安全应用修改
 * 
 * 应用改进计划到项目，支持回滚
 */

import fs from 'fs';
import path from 'path';
import { snapshot } from './snapshot.js';
import { evaluate } from './evaluator.js';

/**
 * 应用改进计划
 * @param {Array} plan - 改进计划数组
 * @param {string} projectPath - 项目路径
 * @returns {Object} { success, backupId, error }
 */
export async function applyPlan(plan, projectPath) {
  if (!plan || plan.length === 0) {
    return { success: true, backupId: null, changes: [] };
  }

  // 创建快照
  const backupId = Date.now().toString();
  const backupDir = await snapshot(projectPath, backupId);

  const changes = [];

  try {
    for (const action of plan) {
      const result = await applyAction(action, projectPath);
      changes.push({ action, result });

      if (!result.success) {
        throw new Error(`Action failed: ${action.description}`);
      }
    }

    // 验证修改
    console.log(`[Executor] 计划应用成功，共${changes.length}个动作`);

    return { success: true, backupId, changes };

  } catch (err) {
    // 回滚到快照
    console.log(`[Executor] 计划执行失败，回滚: ${err.message}`);
    await restoreSnapshot(backupDir, projectPath);

    return { success: false, backupId, error: err.message, changes };
  }
}

/**
 * 应用单个动作
 */
async function applyAction(action, projectPath) {
  const { type, file, description } = action;
  const filePath = path.join(projectPath, file);

  try {
    switch (type) {
      case 'add':
        // 创建新文件或目录
        await fs.promises.mkdir(path.dirname(filePath), { recursive: true });
        await fs.promises.writeFile(filePath, description || '', 'utf8');
        return { success: true };

      case 'delete':
        // 删除文件或目录
        await fs.promises.rm(filePath, { recursive: true, force: true });
        return { success: true };

      case 'fix':
        // 简单修复（这里简化处理）
        console.log(`[Executor] Fix: ${file}`);
        return { success: true };

      case 'refactor':
        // 重构（需要更复杂的实现）
        console.log(`[Executor] Refactor: ${file}`);
        return { success: true };

      default:
        console.log(`[Executor] Unknown action: ${type}`);
        return { success: false, error: `Unknown type: ${type}` };
    }
  } catch (err) {
    return { success: false, error: err.message };
  }
}

export default { applyPlan };

/**
 * goalParser.js - 目标解析与量化指标
 * 将自然语言目标转换为可量化的metrics数组
 */

const METRIC_TYPES = {
  ESLINT: 'eslint',
  TEST: 'test',
  COMPLEXITY: 'complexity',
  LLM: 'llm'
};

/**
 * 解析目标文本，返回metrics数组
 * @param {string} goalText - 自然语言目标描述
 * @returns {Array} metrics数组
 */
function parseGoal(goalText) {
  const text = goalText.toLowerCase();
  const metrics = [];

  // ESLint检查
  if (text.includes('eslint') || text.includes('代码规范') || text.includes('lint')) {
    metrics.push({
      type: METRIC_TYPES.ESLINT,
      target: 0, // 期望0个错误
      weight: 1.0
    });
  }

  // 测试通过率
  if (text.includes('测试') || text.includes('test') || text.includes('通过率')) {
    const testMatch = text.match(/(\d+)%?/);
    const target = testMatch ? parseInt(testMatch[1]) : 100;
    metrics.push({
      type: METRIC_TYPES.TEST,
      target: target,
      weight: 1.0
    });
  }

  // 圈复杂度
  if (text.includes('复杂度') || text.includes('complexity')) {
    const complexMatch = text.match(/(\d+)/);
    const target = complexMatch ? parseInt(complexMatch[1]) : 10;
    metrics.push({
      type: METRIC_TYPES.COMPLEXITY,
      target: target,
      weight: 0.8
    });
  }

  // LLM评估
  if (text.includes('llm') || text.includes('代码质量') || text.includes('质量评估')) {
    metrics.push({
      type: METRIC_TYPES.LLM,
      target: 80, // 80分以上
      weight: 1.0
    });
  }

  // 默认添加ESLint
  if (metrics.length === 0) {
    metrics.push({
      type: METRIC_TYPES.ESLINT,
      target: 0,
      weight: 1.0
    });
  }

  return metrics;
}

export { parseGoal, METRIC_TYPES };

/**
 * 计划生成模块 - LLM驱动生成改进计划
 * 
 * 根据当前项目状态和目标，生成下一步改进计划
 */

import { callLLM } from './llm.js'; // 假设的LLM调用

/**
 * 生成改进计划
 * @param {string} projectPath - 项目路径
 * @param {string} goal - 改进目标
 * @param {Array} metrics - 量化指标
 * @param {Array} previousAttempts - 之前尝试的计划
 * @returns {Array} 改进计划数组
 */
export async function generatePlan(projectPath, goal, metrics, previousAttempts = []) {
  // 获取项目摘要
  const summary = await getProjectSummary(projectPath);

  // 构建提示
  const prompt = buildPrompt(summary, goal, metrics, previousAttempts);

  try {
    // 调用LLM生成计划
    const response = await callLLM(prompt);
    return parsePlanResponse(response);
  } catch (e) {
    // LLM调用失败，返回默认计划
    console.log('[Planner] LLM调用失败，使用默认计划:', e.message);
    return generateDefaultPlan(goal);
  }
}

/**
 * 获取项目摘要
 */
async function getProjectSummary(projectPath) {
  const fs = await import('fs');
  const path = await import('path');

  // 简单实现：列出关键文件
  const keyFiles = [
    'package.json',
    'requirements.txt',
    'src/index.js',
    'src/main.py',
    'Cargo.toml',
    'go.mod'
  ];

  const existing = keyFiles.filter(f => {
    try {
      return fs.existsSync(path.join(projectPath, f));
    } catch { return false; }
  });

  return {
    path: projectPath,
    keyFiles: existing,
    fileCount: countFiles(projectPath)
  };
}

function countFiles(dir) {
  // 简化实现
  return '多个';
}

/**
 * 构建LLM提示
 */
function buildPrompt(summary, goal, metrics, previousAttempts) {
  const attemptsStr = previousAttempts.length > 0 
    ? previousAttempts.map(p => p.description).join('; ')
    : '无';

  return `
项目摘要: ${JSON.stringify(summary)}
改进目标: ${goal}
量化指标: ${JSON.stringify(metrics)}
之前尝试: ${attemptsStr}

请生成下一步具体的改进计划（JSON数组），每个动作包含:
- type: refactor | rename | delete | add | fix
- file: 文件路径
- description: 描述
- priority: 1-5

只输出JSON数组，不要其他内容。
`;
}

/**
 * 解析LLM响应
 */
function parsePlanResponse(response) {
  try {
    const plans = JSON.parse(response);
    return Array.isArray(plans) ? plans : [];
  } catch {
    return [];
  }
}

/**
 * 生成默认计划
 */
function generateDefaultPlan(goal) {
  // 根据目标关键词生成简单计划
  if (/eslint|规范/i.test(goal)) {
    return [{ type: 'fix', file: '.eslintrc.json', description: '配置ESLint规则', priority: 3 }];
  }
  if (/test|测试/i.test(goal)) {
    return [{ type: 'add', file: 'tests/', description: '添加测试文件', priority: 3 }];
  }
  return [{ type: 'refactor', file: 'src/', description: '重构代码', priority: 3 }];
}

export default { generatePlan };

/**
 * snapshot.js - 项目快照与回滚
 * 创建和管理项目快照，支持版本回滚
 */

import { execSync } from 'child_process';
import { existsSync, mkdirSync, rmSync, readdirSync, statSync, cpSync } from 'fs';
import { join, basename } from 'path';

const SNAPSHOT_DIR = '.auto-improve-snapshots';

/**
 * 获取快照目录路径
 * @param {string} projectPath 
 * @returns {string}
 */
function getSnapDir(projectPath) {
  return join(projectPath, SNAPSHOT_DIR);
}

/**
 * 创建项目快照
 * @param {string} projectPath - 项目路径
 * @param {string} snapshotId - 快照ID（可选，默认时间戳）
 * @returns {string} 快照目录路径
 */
function snapshot(projectPath, snapshotId = null) {
  const id = snapshotId || Date.now().toString();
  const snapDir = join(getSnapDir(projectPath), id);

  if (!existsSync(snapDir)) {
    mkdirSync(snapDir, { recursive: true });
  }

  // 排除node_modules和.git
  const excludeDirs = ['node_modules', '.git', 'dist', 'coverage', '.next', 'dist'];
  const items = readdirSync(projectPath).filter(item => !excludeDirs.includes(item));

  for (const item of items) {
    const src = join(projectPath, item);
    const dest = join(snapDir, item);
    try {
      cpSync(src, dest, { recursive: true });
    } catch (e) {
      console.warn(`Skip ${item}: ${e.message}`);
    }
  }

  return snapDir;
}

/**
 * 恢复快照
 * @param {string} snapDir - 快照目录路径
 * @param {string} projectPath - 项目路径
 */
function restoreSnapshot(snapDir, projectPath) {
  if (!existsSync(snapDir)) {
    throw new Error(`Snapshot not found: ${snapDir}`);
  }

  // 备份当前状态到临时目录
  const backupDir = join(getSnapDir(projectPath), '.backup-temp');
  try {
    const items = readdirSync(projectPath).filter(item => 
      !['node_modules', '.git', SNAPSHOT_DIR].includes(item)
    );
    for (const item of items) {
      cpSync(join(projectPath, item), join(backupDir, item), { recursive: true });
    }
  } catch (e) {
    console.warn('Backup failed, continue anyway');
  }

  // 恢复快照内容到项目目录
  const snapItems = readdirSync(snapDir);
  for (const item of snapItems) {
    const src = join(snapDir, item);
    const dest = join(projectPath, item);
    try {
      cpSync(src, dest, { recursive: true });
    } catch (e) {
      console.warn(`Restore ${item} failed: ${e.message}`);
    }
  }
}

/**
 * 清理旧快照
 * @param {string} projectPath - 项目路径
 * @param {number} keepCount - 保留最近快照数量，默认3
 */
function cleanupSnapshots(projectPath, keepCount = 3) {
  const baseDir = getSnapDir(projectPath);
  if (!existsSync(baseDir)) return;

  const dirs = readdirSync(baseDir)
    .map(name => ({
      name,
      path: join(baseDir, name),
      mtime: statSync(join(baseDir, name)).mtime.getTime()
    }))
    .filter(d => statSync(d.path).isDirectory() && !d.name.startsWith('.'))
    .sort((a, b) => b.mtime - a.mtime);

  // 保留最近的快照
  const toDelete = dirs.slice(keepCount);
  for (const dir of toDelete) {
    try {
      rmSync(dir.path, { recursive: true, force: true });
      console.log(`Deleted old snapshot: ${dir.name}`);
    } catch (e) {
      console.warn(`Failed to delete ${dir.name}: ${e.message}`);
    }
  }
}

export { snapshot, restoreSnapshot, cleanupSnapshots, getSnapDir };
